    };

    for (int i = threshold + 1; i <= n; i++) {
        for (int j = 2 * i; j <= n; j += i) {
            unite.accept(i, j);
        }
    }

    for (int i = 0; i < queries.length; i++) {
        answer[i] = find.apply(queries[i][0]) == find.apply(queries[i][1]);
    }

    return answer;
}
